import android.util.Log
import okhttp3.logging.HttpLoggingInterceptor
import timber.log.Timber
import java.util.concurrent.ConcurrentHashMap
import kotlin.system.measureTimeMillis

class ComprehensiveLogger {
    companion object {
        private const val TAG = "AppLogger"
        private val loggedRequests = ConcurrentHashMap<String, Long>()
        
        fun init() {
            Timber.plant(object : Timber.DebugTree() {
                override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
                    when (priority) {
                        Log.VERBOSE -> Log.v(tag, message, t)
                        Log.DEBUG -> Log.d(tag, message, t)
                        Log.INFO -> Log.i(tag, message, t)
                        Log.WARN -> Log.w(tag, message, t)
                        Log.ERROR -> Log.e(tag, message, t)
                        else -> Log.println(priority, tag, message)
                    }
                    super.log(priority, tag, message, t)
                }
            })
        }
        
        fun logAuthAttempt(userId: String?, success: Boolean, reason: String? = null) {
            val message = if (success) {
                "AUTH SUCCESS: User $userId authenticated successfully"
            } else {
                "AUTH FAILED: User $userId failed to authenticate. Reason: $reason"
            }
            Timber.tag(TAG).i(message)
        }
        
        fun logDatabaseQuery(query: String, parameters: Map<String, Any>?, durationMs: Long) {
            val params = if (parameters.isNullOrEmpty()) {
                "No parameters"
            } else {
                parameters.entries.joinToString(", ") { "${it.key}=${it.value}" }
            }
            val message = "DB QUERY: $query | Parameters: $params | Duration: ${durationMs}ms"
            Timber.tag(TAG).v(message)
        }
        
        fun logApiRequest(
            url: String,
            method: String,
            headers: Map<String, String>?,
            body: String?,
            durationMs: Long
        ) {
            val headerString = headers?.entries?.joinToString(", ") { "${it.key}: ${it.value}" }
            val message = "API REQUEST: $method $url | Headers: $headerString | Body: $body | Duration: ${durationMs}ms"
            Timber.tag(TAG).v(message)
        }
        
        fun logException(exception: Throwable, context: String? = null) {
            val message = if (context.isNullOrEmpty()) {
                "EXCEPTION: ${exception.javaClass.simpleName}: ${exception.message}"
            } else {
                "EXCEPTION in $context: ${exception.javaClass.simpleName}: ${exception.message}"
            }
            Timber.tag(TAG).e(exception, message)
        }
        
        fun logApiCallStart(requestId: String) {
            loggedRequests[requestId] = System.currentTimeMillis()
            Timber.tag(TAG).v("API CALL STARTED: $requestId")
        }
        
        fun logApiCallEnd(requestId: String) {
            val startTime = loggedRequests.remove(requestId)
            if (startTime != null) {
                val duration = System.currentTimeMillis() - startTime
                Timber.tag(TAG).v("API CALL ENDED: $requestId | Duration: ${duration}ms")
            }
        }
        
        fun logDatabaseOperation(operation: String, durationMs: Long) {
            Timber.tag(TAG).v("DB OPERATION: $operation | Duration: ${durationMs}ms")
        }
        
        fun logUserAction(action: String, userId: String? = null) {
            val message = if (userId.isNullOrEmpty()) {
                "USER ACTION: $action"
            } else {
                "USER ACTION: $action by user $userId"
            }
            Timber.tag(TAG).i(message)
        }
        
        fun logPerformanceMetric(metricName: String, value: Any) {
            Timber.tag(TAG).v("PERFORMANCE: $metricName = $value")
        }
    }
}

class LoggingInterceptor : HttpLoggingInterceptor.Logger {
    override fun log(message: String) {
        Timber.tag("HTTP_LOG").v(message)
    }
}

fun <T> logExecutionTime(operationName: String, block: () -> T): T {
    val duration = measureTimeMillis {
        Timber.tag(ComprehensiveLogger.TAG).v("STARTING: $operationName")
    }
    val result = block()
    Timber.tag(ComprehensiveLogger.TAG).v("COMPLETED: $operationName in ${duration}ms")
    return result
}

