        fun logQueryWithDuration(query: String, parameters: Map<String, Any>?, durationMs: Long) {
            ComprehensiveLogger.logDatabaseQuery(query, parameters, durationMs)
        }
    }
}

class NetworkLogger {
    companion object {
        fun logRequest(url: String, method: String, headers: Map<String, String>?, body: String?) {
            val duration = measureTimeMillis {
                ComprehensiveLogger.logApiRequest(url, method, headers, body, 0)
            }
            ComprehensiveLogger.logApiRequest(url, method, headers, body, duration)
        }
        
        fun logResponse(url: String, statusCode: Int, headers: Map<String, String>?, body: String?) {
            Timber.tag(ComprehensiveLogger.TAG).v("API RESPONSE: $url | Status: $statusCode | Body: $body")
        }
    }
}

class ExceptionHandler : Thread.UncaughtExceptionHandler {
    private val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
    
    override fun uncaughtException(thread: Thread, exception: Throwable) {
        ComprehensiveLogger.logException(exception, "Uncaught Exception in ${thread.name}")
        defaultHandler?.uncaughtException(thread, exception)
    }
}

fun setupLogging() {
    ComprehensiveLogger.init()
    Thread.setDefaultUncaughtExceptionHandler(ExceptionHandler())
}